using Microsoft.EntityFrameworkCore;using Microsoft.EntityFrameworkCore.Metadata.Builders;using NutriCasa.Domain.Entities;
namespace NutriCasa.Infrastructure.Persistence.Configurations;
public class AiInteractionConfiguration : IEntityTypeConfiguration<AiInteraction>{public void Configure(EntityTypeBuilder<AiInteraction> builder){builder.ToTable("ai_interactions");builder.HasKey(e => e.Id);builder.Property(e => e.Id).HasColumnName("interaction_id").HasDefaultValueSql("uuid_generate_v4()");builder.Property(e => e.InteractionType).HasConversion<string>().HasMaxLength(40);builder.Property(e => e.PromptVersion).HasMaxLength(20).IsRequired();builder.Property(e => e.ModelUsed).HasMaxLength(50).IsRequired();builder.Property(e => e.EstimatedCostUsd).HasColumnType("decimal(10,6)");builder.Property(e => e.PromptHash).HasMaxLength(64);builder.Property(e => e.RequestPayload).HasColumnType("jsonb");builder.Property(e => e.ResponsePayload).HasColumnType("jsonb");builder.HasOne(e => e.User).WithMany().HasForeignKey(e => e.UserId).OnDelete(DeleteBehavior.SetNull);builder.HasIndex(e => new { e.UserId, e.CreatedAt });builder.HasIndex(e => e.PromptHash);}}
